import React, { useState } from 'react';

function Counter() {
  const [count, setCount] = useState(0);
  return (
    <div>
      <p>Say: {count}</p>
      <button onClick={() => setCount(count + 1)}>Artır</button>
      <button onClick={() => setCount(count - 1)}>Azalt</button>
      <button onClick={() => setCount(0)}>Sıfırla</button>
    </div>
  );
}

console.log('Sadə sayaç komponenti yaradıldı');

import React, { useState } from 'react';

function NameDisplay() {
  const [name, setName] = useState('Aysel');
  const changeName = () => {
    setName(name === 'Aysel' ? 'React Öyrənən' : 'Aysel');
  };
  return (
    <div>
      <p>Ad: {name}</p>
      <button onClick={changeName}>Adı dəyiş</button>
    </div>
  );
}

console.log('String state komponenti yaradıldı');

import React, { useState } from 'react';

function ToggleButton() {
  const [isOn, setIsOn] = useState(false);
  return (
    <div>
      <p>Vəziyyət: {isOn ? 'Açıq' : 'Bağlı'}</p>
      <button onClick={() => setIsOn(!isOn)}>
        {isOn ? 'Bağla' : 'Aç'}
      </button>
    </div>
  );
}

console.log('Toggle komponenti yaradıldı');

import React, { useState } from 'react';

function UserProfile() {
  const [user, setUser] = useState({ name: 'Aysel', age: 20 });
  const updateAge = () => {
    setUser({ ...user, age: user.age + 1 });
  };
  return (
    <div>
      <p>Ad: {user.name}</p>
      <p>Yaş: {user.age}</p>
      <button onClick={updateAge}>Yaşı artır</button>
    </div>
  );
}

console.log('Obyekt state komponenti yaradıldı');

import React, { useState } from 'react';

function FunctionalUpdateCounter() {
  const [count, setCount] = useState(0);
  const incrementFive = () => {
    for (let i = 0; i < 5; i++) {
      setCount(prevCount => prevCount + 1);
    }
  };
  return (
    <div>
      <p>Say: {count}</p>
      <button onClick={incrementFive}>5 artır</button>
    </div>
  );
}

